<script>
// @ is an alias to /src
import html2canvas from "html2canvas";
export default {
  name: "Home",
  components: {},
  data() {
    return {
      tableData: [
        {
          Input: "0",
          Icon: "./assets/white.png",
          Description: "Control bit (low level trigger)",
        },
        {
          Input: "1",
          Icon: "black-control",
          Description: "Control bit (high level trigger)",
        },
        {
          Input: "2",
          Icon: "Not-gate",
          Description:
            "NOT-gate(Note that each line must contain exactly one NOT-gate.)",
        },
        {
          Input: "3",
          Icon: "Wire-gate",
          Description: "Wire gate",
        },
      ],
      isDecimal: false,
      GateSet: "",
      list1: [{ gate: "1" }],
      list2: [],
      drag: true,
      originobj: null,
      Dragobj: null,
      Dragindex: 0,
      bit: 3,
      gatecount: 1,
      hyperbit: [],
      state: 1,
      list3: [],
      Dict: ["0", "0", "0"],
      Input_Gate: [],
      Truth_TableList: [],
      Truth_Table: [],
      Output_TableList: [],
      Output_Tbale: [],
    };
  },
  methods: {
    log: function (evt) {
      window.console.log(evt);
    },
    test: function (i, n) {
      let obj = n[i - 1];
      this.$set(obj, "gate", "1");
      console.log(n[i - 1].gate);
    },
    onDragstart(event) {
      // console.log("start");
      // console.log(event);
      this.originobj = event.target._prevClass;
      this.Dragobj = null;
      this.Dragindex = 0;
    },
    onDrop() {},
    onDragend() {
      if (this.Dragobj != null) {
        if (this.originobj === "white-control")
          this.$set(this.Dragobj, "gate", "0");
        else if (this.originobj === "black-control")
          this.$set(this.Dragobj, "gate", "1");
        else if (this.originobj === "not-gate")
          this.$set(this.Dragobj, "gate", "2");
        this.state = this.state * -1;
      }
    },
    onDragover(event) {
      event.preventDefault();
    },
    onDragover2(event, i, n) {
      event.preventDefault();
      this.Dragobj = n[i - 1];
      this.Dragindex = i;
    },
    Binary() {
      //this.list2[1] = [{ gate: "1" }, { gate: "1" }, { gate: "2" }];
      let tmplist = [];
      var tmp = this.GateSet.toString().split(" ");
      this.bit = tmp[0].length;
      for (let i = 0; i < tmp.length; i++) {
        if (tmp[i] == "") {
          continue;
        }
        tmplist.push([]);
        for (let j = 0; j < tmp[0].length; j++) {
          tmplist[i].push({ gate: tmp[i][j] });
        }
      }
      this.list2 = tmplist;
      this.Truth_Table = [];
      this.Init_Count(0);
      this.SolveGate();
    },
    Init_Count(i) {
      let tmp = [];
      if (i == this.bit) {
        this.Dict.forEach((e, index) => {
          tmp["I" + (index + 1)] = e;
        }); //�M��gate

        this.Truth_Table.push(tmp);
        return;
      }
      this.Dict[i] = "0";
      this.Init_Count(i + 1);
      this.Dict[i] = "1";
      this.Init_Count(i + 1);
    },
    Init_Count2Decimal() {
      this.Truth_Table.forEach((e, index) => {
        e["D_I"] = index.toString();
        e["D_O"] = index.toString();
      });
    },
    SolveGate() {
      let not_gate_index = 0;
      this.Truth_Table.forEach((e) => {
        for (let i = 0; i < this.list2.length; i++) {
          let wrong = 0; //bit�Mgate�O�_�ǰt
          for (let j = 0; j < this.list2[i].length; j++) {
            if (i == 0) e["O" + (j + 1)] = e["I" + (j + 1)];
            if (this.list2[i][j].gate == "2") {
              not_gate_index = j;
            } else if (this.list2[i][j].gate == "3") {
              continue;
            } else if (e["O" + (j + 1)] != this.list2[i][j].gate) {
              wrong = 1; //�����ŦX��gate
            }
          }
          if (wrong == 0) {
            if (e["O" + (not_gate_index + 1)] == "0") {
              e["O" + (not_gate_index + 1)] = "1";
            } else {
              e["O" + (not_gate_index + 1)] = "0";
            }
            //�ǰt �ݭn��notgate����m�ç������bit½��
          }
        }
        // console.log(e);
      });
    },
    SolveGate2Decimal() {},
    Save() {
      let cloneDom = this.$refs.imageToFile;
      // let height = cloneDom.offsetHeight;// ������e����
      // console.log(cloneDom.scrollWidth, cloneDom.scrollHeight);
      html2canvas(this.$refs.imageToFile, {
        width: cloneDom.scrollWidth,
        // windowWidth: cloneDom.scrollWidth, // ���X�b��V�u�ʱ����e
        // windowHeight: cloneDom.scrollHeight, // ���Y�b��V�u�ʱ����e
        x: 0, // ����e����
        scrollY: 0,
      }).then((canvas) => {
        // �Ĥ@�ӰѼƬO�ݭn�ͦ��I�Ϫ�����,�ĤG�ӬO�ۤv�ݭn�t�m���Ѽ�,�e����
        let dataURL = canvas.toDataURL("image/png");
        if (dataURL !== "") {
          //�U���Ϥ�
          let alink = document.createElement("a");
          alink.href = dataURL;
          alink.download = "circuit diagram.png";
          alink.click();
        }
      });
    },
    clear() {
      this.list2 = [];
      this.GateSet = "";
      this.Truth_Table = [];
    },
    Decimal() {
      this.Init_Count2Decimal(0);
    },
    focusout() {
      this.$refs.Binary.disabled = 1;
    },
  },
  watch: {
    state: function () {},
    bit: function (params) {
      let tmp = [],
        tmp2 = [];
      for (let i = 0; i < params; i++) {
        tmp.push({ name: "I" + (i + 1), prop: "I" + (i + 1) });
        tmp2.push({ name: "O" + (i + 1), prop: "O" + (i + 1) });
      }
      this.Truth_TableList = tmp;
      this.Output_TableList = tmp2;
      if (this.isDecimal == true) {
        this.Truth_TableList.push({ name: "D_I", prop: "D_I" });
        this.Output_TableList.push({ name: "D_O", prop: "D_O" });
      }
    },
    isDecimal: function (p) {
      if (p == true) {
        this.Truth_TableList.push({ name: "D_I", prop: "D_I" });
        this.Output_TableList.push({ name: "D_O", prop: "D_O" });
      } else {
        this.Truth_TableList.pop({ name: "D_I", prop: "D_I" });
        this.Output_TableList.pop({ name: "D_O", prop: "D_O" });
      }
    },
    Truth_Table: function (p) {
      // if (this.isDecimal == true) { // 不管怎麼樣都會計算Decimal
      p.forEach((element, index) => {
        element["D_I"] = index.toString();
        let out = 0;
        for (let i = 0; i < this.bit; i++) {
          out =
            out +
            Number(element["O" + (i + 1)]) * Math.pow(2, this.bit - i - 1);
        }
        element["D_O"] = out.toString();
      });
      // }
    },
  },
  computed: {},
  mounted: function () {
    let tmp = [],
      tmp2 = [];
    for (let i = 0; i < this.bit; i++) {
      tmp.push({ name: "I" + (i + 1), prop: "I" + (i + 1) });
      tmp2.push({ name: "O" + (i + 1), prop: "O" + (i + 1) });
    }
    this.Truth_TableList = tmp;
    this.Output_TableList = tmp2;
    // this.Init_Count(0);
    // this.SolveGate();
  },
};
</script>

